USE IP1_PROMOREPORTLINE;
SET NOCOUNT ON;
GO
IF OBJECT_ID('M_Product','U') IS NOT NULL DROP TABLE M_Product;
CREATE TABLE M_Product (id INT IDENTITY PRIMARY KEY, company NVARCHAR(200), category NVARCHAR(150), sub_category NVARCHAR(200), brand NVARCHAR(150), size_group NVARCHAR(100), size NVARCHAR(100), pack NVARCHAR(100), variant NVARCHAR(MAX));
GO
GO
IF OBJECT_ID('M_Store','U') IS NOT NULL DROP TABLE M_Store;
CREATE TABLE M_Store (id INT IDENTITY PRIMARY KEY, seq INT, channel_mt_kae NVARCHAR(20), channel NVARCHAR(120), account NVARCHAR(300), branch NVARCHAR(200), province NVARCHAR(100), warehouse NVARCHAR(50), ism_zone NVARCHAR(50), hq_code NVARCHAR(50), ship_to NVARCHAR(50), sold_to NVARCHAR(100), store_code NVARCHAR(50), store_type NVARCHAR(120), master_ism NVARCHAR(50));
GO
GO
IF OBJECT_ID('report_photos','U') IS NOT NULL DROP TABLE report_photos;
IF OBJECT_ID('report_items','U') IS NOT NULL DROP TABLE report_items;
IF OBJECT_ID('reports','U') IS NOT NULL DROP TABLE reports;
IF OBJECT_ID('bot_sessions','U') IS NOT NULL DROP TABLE bot_sessions;
IF OBJECT_ID('report_subtypes','U') IS NOT NULL DROP TABLE report_subtypes;
IF OBJECT_ID('report_types','U') IS NOT NULL DROP TABLE report_types;
IF OBJECT_ID('topics','U') IS NOT NULL DROP TABLE topics;
CREATE TABLE topics (id INT IDENTITY PRIMARY KEY, code NVARCHAR(50), name_th NVARCHAR(100), sort_order INT);
CREATE TABLE report_types (id INT IDENTITY PRIMARY KEY, topic_id INT, name NVARCHAR(200));
CREATE TABLE report_subtypes (id INT IDENTITY PRIMARY KEY, report_type_id INT, name NVARCHAR(200));
CREATE TABLE reports (id BIGINT IDENTITY PRIMARY KEY, line_user_id NVARCHAR(50), topic NVARCHAR(100), channel NVARCHAR(50), account NVARCHAR(300), branch NVARCHAR(200), company NVARCHAR(200), start_date DATE, end_date DATE, note NVARCHAR(MAX), status NVARCHAR(20) DEFAULT 'submitted', created_at DATETIME2 DEFAULT SYSDATETIME());
CREATE TABLE report_items (id BIGINT IDENTITY PRIMARY KEY, report_id BIGINT, category NVARCHAR(150), sub_category NVARCHAR(200), brand NVARCHAR(150), size NVARCHAR(100), pack NVARCHAR(100), variant NVARCHAR(200), report_type NVARCHAR(200), report_subtype NVARCHAR(200), detail NVARCHAR(MAX), is_npd BIT DEFAULT 0);
CREATE TABLE report_photos (id BIGINT IDENTITY PRIMARY KEY, report_id BIGINT, photo_data VARBINARY(MAX), photo_type NVARCHAR(20), uploaded_at DATETIME2 DEFAULT SYSDATETIME());
CREATE TABLE bot_sessions (line_user_id NVARCHAR(50) PRIMARY KEY, state NVARCHAR(MAX), updated_at DATETIME2 DEFAULT SYSDATETIME());
GO
SET IDENTITY_INSERT topics ON;
SET IDENTITY_INSERT topics OFF;
SET IDENTITY_INSERT report_types ON;
SET IDENTITY_INSERT report_types OFF;
SET IDENTITY_INSERT report_subtypes ON;
SET IDENTITY_INSERT report_subtypes OFF;
GO